import React from 'react'
import { Arrow, MenuNewWindow } from '@fs/zion-icon'
import { Button, Bleed, colors } from '@fs/zion-ui'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'

const hasWindow = typeof window !== 'undefined'

const navigationBarCss = css`
  align-items: center;
  background-color: ${colors.gray02};
  display: grid;
  grid-template-columns: auto auto;
  justify-content: space-between;
  padding: 4px 20px;
`

const newTabButtonCss = css`
  align-items: center;
  display: grid;
  grid-column-gap: 4px;
  grid-template-columns: 1fr auto;
  height: 100%;
`

export default function HelpOverlaySubnav({ currentArticleUrl, loadArticle }) {
  const [t] = useTranslation()
  return (
    <Bleed sides bottom>
      <div className={navigationBarCss}>
        <Button
          Icon={Arrow}
          iconDirection="backward"
          onClick={() => {
            loadArticle('')
          }}
          data-test="helpOverlayBackButton"
        >
          {t('help-tray.back.button-label', 'Back')}
        </Button>
        <Button
          onClick={() => {
            // FIXME: Keep it in current
            hasWindow && window.open(currentArticleUrl, '_blank')
          }}
          data-test="helpOverlayNewTabButton"
        >
          <span className={newTabButtonCss}>
            <span>{t('help-tray.new-tab.button-label', 'Open in New Tab')}</span>
            <MenuNewWindow size="xs" />
          </span>
        </Button>
      </div>
    </Bleed>
  )
}
